const newData = $items("Webhook")[0].json.body.record; // البيانات الجديدة من الويب هوك
const oldRow = $input.item.json; // البيانات القديمة من السوبابيز

const oldVision = oldRow.metadata.vision_description || "وصف سابق غير متاح";

const images = newData.images || [];
const firstImageUrl = images.length > 0 ? images[0] : null;

return {
  json: {
    listing_id: newData.id,
    content: `الاسم: ${newData.name}\nالموقع: ${newData.location}\nالسعر: ${newData.price}\nالوصف: ${newData.description}\n🌟 وصف المظهر: ${oldVision}`,
    metadata: {
      listing_id: newData.id,
      price: newData.price,
      location: newData.location,
      vision_description: oldVision,
      image_url: firstImageUrl,
      status : newData.status
    }
  }
};

// جلب البيانات الأصلية من عقدة الكود الأولى (تأكد أن اسم العقدة مطابق لاسمها عندك)
const original_data = $items("Code Prepare Data")[0].json; 

// 🌟 جلب الوصف البصري من عقدة Gemini (التغيير هنا في مسار قراءة النص)
const vision_description = $input.item.json.content?.parts?.[0]?.text || "لا يوجد وصف بصري متاح.";

// دمج النصين معاً
const final_content = `${original_data.base_content}\n🌟 الوصف المعماري والبصري: ${vision_description}`;

return {
  json: {
    listing_id: original_data.listing_id,
    content: final_content, 
    metadata: { // تجهيز الـ Metadata لعقدة الحفظ
        listing_id: original_data.listing_id,
        price: original_data.price,
        location: original_data.location,
        vision_description: vision_description,
        image_url: original_data.image_url,
        status : original_data.status
    }
  }
};

// 1. استلام البيانات من الجذر
const payload = $input.item.json;

// 2. الوصول إلى بيانات العقار الموجودة داخل مسار (body -> record)
const record = payload.body.record;

// 3. استخراج الحقول الأساسية
const id = record.id || "بدون_معرف"; 
const name = record.name || "غير محدد";
const description = record.description || "لا يوجد وصف";
const price = record.price || "غير محدد";
const location = record.location || "غير محدد";
const category = record.category || "غير محدد";

// استخراج حالة العقار من قاعدة البيانات وترجمتها للعربية
const rawStatus = record.status || "available"; 
let statusText = "متاح";

if (rawStatus === "sold") {
    statusText = "مباع";
} else if (rawStatus === "booked" || rawStatus === "reserved") {
    statusText = "محجوز";
} else if (rawStatus === "pending") {
    statusText = "قيد المعاينة";
}

// 4. استخراج المواصفات (specs)
const specs = record.specs || {};
let specsText = "";

if (Object.keys(specs).length > 0) {
  specsText = Object.entries(specs)
    .map(([key, value]) => `${key}: ${value}`)
    .join('، ');
} else {
  specsText = "لا يوجد تفاصيل إضافية";
}

// 🌟 5. (الجديد) استخراج رابط الصورة الأولى للذكاء الاصطناعي
const images = record.images || [];
const firstImageUrl = images.length > 0 ? images[0] : null;

// 6. صياغة النص الذكي (Semantic Chunk) ديناميكياً
const ai_content = `حالة العقار الحالي: ${statusText}
- الاسم: ${name}
- التصنيف: ${category}
- الوصف: ${description}
- الموقع: ${location}
- السعر: ${price}
- المواصفات الإضافية: ${specsText}`;

// 7. إرجاع النتيجة
return {
  json: {
    listing_id: id,
    base_content: ai_content, // غيّرنا الاسم لنضيف عليه لاحقاً
    image_url: firstImageUrl, // 🌟 الرابط الذي ستقرأه عقدة Analyze image
    status: rawStatus, 
    price: Number(price), 
    location: location 
  }
};
